class ScoringEngine:
    """
    A class to evaluate and score candidate responses based on predefined rubrics.
    """

    def __init__(self, rubrics):
        """
        Initializes the ScoringEngine with a dictionary of rubrics.

        Args:
            rubrics (dict): A dictionary where keys are question identifiers (e.g., question text)
                           and values are dictionaries containing scoring criteria and weights.
                           Example:
                           {
                               "Explain the difference between lists and tuples in Python": {
                                   "Correctness": {"weight": 0.6, "excellent": "Accurate and complete explanation", "good": "Mostly correct", "fair": "Partially correct", "poor": "Incorrect"},
                                   "Clarity": {"weight": 0.4, "excellent": "Very clear and concise", "good": "Clear", "fair": "Somewhat unclear", "poor": "Unclear"}
                               },
                               "What are decorators in Python and how are they used?": {
                                   "Correctness": {"weight": 0.7, "excellent": "Accurate and complete explanation with examples", "good": "Mostly correct", "fair": "Partially correct", "poor": "Incorrect"},
                                   "Application": {"weight": 0.3, "excellent": "Demonstrates strong understanding of practical applications", "good": "Understands basic applications", "fair": "Limited understanding", "poor": "No understanding"}
                               }
                           }
        """
        self.rubrics = rubrics

    def evaluate_response(self, question, response):
        """
        Evaluates a candidate's response to a specific question based on the rubric.

        Args:
            question (str): The question the candidate answered.
            response (str): The candidate's response.

        Returns:
            dict: A dictionary containing the overall score and scores for each criterion.
                  Returns None if no rubric is found for the question.
                  Example:
                  {
                      "overall_score": 0.85,
                      "Correctness": 0.9,
                      "Clarity": 0.8
                  }
        """
        if question not in self.rubrics:
            print(f"No rubric found for question: {question}")
            return None

        rubric = self.rubrics[question]
        criterion_scores = {}
        overall_score = 0

        for criterion, details in rubric.items():
            weight = details["weight"]
            # The evaluation logic will depend on how you want to evaluate the responses
            # This is a placeholder for a more sophisticated evaluation method (e.g., using NLP)

            # Simplified example: score based on keyword matching
            if criterion == "Correctness":
                if "accurate" in response.lower() and "complete" in response.lower():
                    criterion_score = 1.0  # Excellent
                elif "correct" in response.lower():
                    criterion_score = 0.75 # Good
                elif "partially" in response.lower():
                    criterion_score = 0.5 # Fair
                else:
                    criterion_score = 0.25 # Poor
            elif criterion == "Clarity":
                if "clear" in response.lower() and "concise" in response.lower():
                    criterion_score = 1.0
                elif "clear" in response.lower():
                    criterion_score = 0.75
                elif "unclear" not in response.lower():
                    criterion_score = 0.5
                else:
                    criterion_score = 0.25
            elif criterion == "Application": # added application criterion
                 if "strong understanding" in response.lower():
                     criterion_score = 1.0
                 elif "basic applications" in response.lower():
                     criterion_score = 0.75
                 elif "limited understanding" in response.lower():
                     criterion_score = 0.5
                 else:
                     criterion_score = 0.25
            else:
                criterion_score = 0.5  # Default score

            criterion_scores[criterion] = criterion_score
            overall_score += weight * criterion_score

        return {
            "overall_score": overall_score,
            **criterion_scores
        }

    def score_candidate(self, candidate_name, responses):
        """
        Scores a candidate's responses to all questions based on the rubrics.

        Args:
            candidate_name (str): The name of the candidate.
            responses (dict): A dictionary where keys are question identifiers (e.g., question text)
                              and values are the candidate's responses to those questions.

        Returns:
            dict: A dictionary containing the overall score for the candidate and scores for each question.
                  Returns None if no responses are provided.
                  Example:
                  {
                      "overall_score": 0.825,
                      "Explain the difference between lists and tuples in Python": {"overall_score": 0.85, "Correctness": 0.9, "Clarity": 0.8},
                      "What are decorators in Python and how are they used?": {"overall_score": 0.8, "Correctness": 0.9, "Application": 0.7}
                  }
        """
        if not responses:
            print(f"No responses found for candidate: {candidate_name}")
            return None

        question_scores = {}
        total_weighted_score = 0
        total_weight = 0

        for question, response in responses.items():
            question_score = self.evaluate_response(question, response)
            if question_score:
                question_scores[question] = question_score
                total_weighted_score += question_score["overall_score"]
                total_weight += 1 # each question is weighted equally

        overall_score = total_weighted_score / total_weight if total_weight > 0 else 0

        return {
            "overall_score": overall_score,
            **question_scores
        }



